import React, { useState } from 'react';
import NavBar from '../../components/NavBar/NavBar';
import Waveform from '../../components/Waveform/Waveform';
import './Record.css';

function PlayBack({ duration = 180, currentTime = 0, onContinue, onRestart, onSave }) {
  const [time, setTime] = useState(currentTime);
  const formatTime = (s) => `${Math.floor(s / 60)}:${(s % 60).toString().padStart(2, '0')}`;
  const skip = (amt) => setTime((prev) => Math.max(0, Math.min(prev + amt, duration)));

  return (
    <div className="screen">
      <NavBar active="record" />
      <div className="screen-content">
        <Waveform />
        <p className="timer">{formatTime(time)}/{formatTime(duration)}</p>
        <div className="btn-row">
          <button className="btn btn-skip" onClick={() => skip(-5)}>-0:05</button>
          <button className="btn btn-play">PLAY</button>
          <button className="btn btn-skip" onClick={() => skip(5)}>+0:05</button>
        </div>
        <div className="btn-row">
          <button className="btn btn-continue" onClick={onContinue}>CONTINUE</button>
          <button className="btn btn-restart" onClick={onRestart}>RESTART</button>
          <button className="btn btn-save" onClick={onSave}>SAVE</button>
        </div>
      </div>
    </div>
  );
}

export default PlayBack;
